#include<bits/stdc++.h>
using namespace std;

struct st
{
    int ida, idb, v;
};

bool operator< (st x, st y)
{
    return x.v > y.v;
}

priority_queue<st> q;

int a[100005], b[100005];

int main()
{
    int n;
    cin >> n;
    for(int i = 1; i <= n; i++)
        cin >> a[i];
    for(int i = 1; i <= n; i++)
        cin >> b[i];
    for(int i = 1; i <= n; i++)
        q.push({i, 1, a[i] + b[1]});
    for(int i = 1; i <= n; i++)
    {
        st t = q.top();
        q.pop();
        cout << t.v << ' ';
        q.push({t.ida, t.idb + 1, a[t.ida] + b[t.idb + 1]});
    }
}
